namespace RecipeShare.Models;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public string Ingredients { get; set; } = string.Empty;
    public string Steps { get; set; } = string.Empty;
    public int TotalRating { get; set; }
    public int RatingCount { get; set; }
    public double AverageRating => RatingCount > 0 ? (double)TotalRating / RatingCount : 0;
}

using RecipeShare.Models;

namespace RecipeShare.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe { Id = 1, Title = "Classic Margherita Pizza", Category = "Italian", Ingredients = "Pizza dough, Fresh mozzarella, San Marzano tomatoes, Fresh basil, Olive oil", Steps = "1. Preheat oven to 475°F\n2. Roll out dough\n3. Spread crushed tomatoes\n4. Add torn mozzarella\n5. Bake 10-12 minutes\n6. Top with fresh basil" },
        new Recipe { Id = 2, Title = "Spaghetti Carbonara", Category = "Italian", Ingredients = "Spaghetti, Guanciale, Eggs, Pecorino Romano, Black pepper", Steps = "1. Cook spaghetti al dente\n2. Crisp guanciale in a pan\n3. Whisk eggs with grated pecorino\n4. Toss hot pasta with guanciale\n5. Remove from heat, stir in egg mixture\n6. Season with black pepper" },
        new Recipe { Id = 3, Title = "Chicken Tikka Masala", Category = "Indian", Ingredients = "Chicken thighs, Yogurt, Garam masala, Tomato sauce, Heavy cream, Ginger, Garlic", Steps = "1. Marinate chicken in yogurt and spices\n2. Grill or broil chicken pieces\n3. Sauté ginger and garlic\n4. Add tomato sauce and spices\n5. Simmer, add cream\n6. Add chicken, cook 5 minutes" },
        new Recipe { Id = 4, Title = "Vegetable Pad Thai", Category = "Thai", Ingredients = "Rice noodles, Tofu, Bean sprouts, Peanuts, Lime, Tamarind paste, Fish sauce", Steps = "1. Soak rice noodles in warm water\n2. Press and cube tofu, pan-fry until golden\n3. Mix tamarind, fish sauce, sugar for sauce\n4. Stir-fry vegetables\n5. Add noodles and sauce\n6. Top with peanuts, lime, bean sprouts" },
        new Recipe { Id = 5, Title = "Beef Tacos", Category = "Mexican", Ingredients = "Ground beef, Taco shells, Lettuce, Tomatoes, Cheese, Sour cream, Cumin, Chili powder", Steps = "1. Season beef with cumin and chili powder\n2. Brown beef in skillet\n3. Warm taco shells\n4. Dice tomatoes and shred lettuce\n5. Assemble tacos with toppings\n6. Serve with sour cream" },
        new Recipe { Id = 6, Title = "Guacamole", Category = "Mexican", Ingredients = "Avocados, Lime juice, Red onion, Cilantro, Jalapeño, Salt", Steps = "1. Halve and pit avocados\n2. Mash to desired consistency\n3. Dice onion, jalapeño, cilantro\n4. Mix everything together\n5. Add lime juice and salt\n6. Serve immediately with chips" },
        new Recipe { Id = 7, Title = "Tom Yum Soup", Category = "Thai", Ingredients = "Shrimp, Lemongrass, Galangal, Kaffir lime leaves, Mushrooms, Chili paste, Fish sauce", Steps = "1. Boil water with lemongrass and galangal\n2. Add mushrooms and lime leaves\n3. Add chili paste and fish sauce\n4. Add shrimp, cook until pink\n5. Finish with lime juice\n6. Garnish with cilantro" },
        new Recipe { Id = 8, Title = "Chocolate Lava Cake", Category = "Desserts", Ingredients = "Dark chocolate, Butter, Eggs, Sugar, Flour, Vanilla extract", Steps = "1. Melt chocolate and butter together\n2. Whisk eggs and sugar until fluffy\n3. Fold in chocolate mixture\n4. Add flour and vanilla\n5. Pour into greased ramekins\n6. Bake at 425°F for 12-14 minutes" },
    };

    private int _nextId = 9;

    public IReadOnlyList<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().Order().ToList();
    }

    public IReadOnlyList<Recipe> GetByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public Recipe? GetById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            recipe.TotalRating += stars;
            recipe.RatingCount++;
        }
    }

    public Recipe Add(string title, string category, string ingredients, string steps)
    {
        var recipe = new Recipe
        {
            Id = _nextId++,
            Title = title,
            Category = category,
            Ingredients = ingredients,
            Steps = steps
        };
        _recipes.Add(recipe);
        return recipe;
    }
}

