arguments.new_str:
@page "/"

<PageTitle>RecipeShare - Home</PageTitle>

<h1>Welcome to RecipeShare</h1>
<p class="lead">Discover and share delicious recipes from around the world.</p>

<h2>Browse by Category</h2>
<div class="row">
    @foreach (var category in Categories)
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@category</h5>
                    <a href="recipes/@category.ToLower()" class="btn btn-primary">View Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Inject] private RecipeShare.Services.RecipeService RecipeService { get; set; } = default!;

    private IReadOnlyList<string> Categories { get; set; } = [];

    protected override void OnInitialized()
    {
        Categories = RecipeService.GetCategories();
    }
}

arguments.file_text:
@page "/recipes"
@page "/recipes/{Category}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>Recipes - @(Category ?? "All Categories")</PageTitle>

@if (string.IsNullOrEmpty(Category))
{
    <h1>All Categories</h1>
    <ul>
        @foreach (var cat in RecipeService.GetCategories())
        {
            <li><a href="recipes/@cat.ToLower()">@cat</a></li>
        }
    </ul>
}
else
{
    <h1>@Category Recipes</h1>
    <a href="recipes" class="btn btn-outline-secondary mb-3">&larr; All Categories</a>

    var recipes = RecipeService.GetByCategory(Category);
    @if (recipes.Count == 0)
    {
        <p>No recipes found in this category.</p>
    }
    else
    {
        <div class="row">
            @foreach (var recipe in recipes)
            {
                <div class="col-md-6 mb-3">
                    <div class="card">
                        <div class="card-body">
                            <h5 class="card-title">@recipe.Title</h5>
                            <p class="text-muted">
                                @if (recipe.RatingCount > 0)
                                {
                                    <span>@recipe.AverageRating.ToString("0.0") ★ (@recipe.RatingCount ratings)</span>
                                }
                                else
                                {
                                    <span>No ratings yet</span>
                                }
                            </p>
                            <a href="recipe/@recipe.Id" class="btn btn-primary">View Recipe</a>
                        </div>
                    </div>
                </div>
            }
        </div>
    }
}

@code {
    [Parameter] public string? Category { get; set; }
}

@page "/recipe/{Id:int}"
@inject RecipeShare.Services.RecipeService RecipeService

@if (Recipe is null)
{
    <PageTitle>Recipe Not Found</PageTitle>
    <h1>Recipe not found</h1>
    <p>The recipe you're looking for doesn't exist.</p>
}
else
{
    <PageTitle>@Recipe.Title - RecipeShare</PageTitle>

    <a href="recipes/@Recipe.Category.ToLower()" class="btn btn-outline-secondary mb-3">&larr; Back to @Recipe.Category</a>

    <h1>@Recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@Recipe.Category</span>

    <h3>Ingredients</h3>
    <ul>
        @foreach (var ingredient in Recipe.Ingredients.Split(',', StringSplitOptions.TrimEntries))
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in Recipe.Steps.Split('\n', StringSplitOptions.RemoveEmptyEntries))
        {
            var text = step.TrimStart();
            if (text.Length > 2 && text[1] == '.')
                text = text[3..];
            <li>@text</li>
        }
    </ol>

    <hr />
    <h4>Rate this Recipe</h4>
    <StarRating RecipeId="Recipe.Id" />
}

@code {
    [Parameter] public int Id { get; set; }

    private RecipeShare.Models.Recipe? Recipe { get; set; }

    protected override void OnInitialized()
    {
        Recipe = RecipeService.GetById(Id);
    }
}

@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (HoverRating ?? SelectedRating) ? "filled" : "")"
              @onclick="() => SubmitRating(star)"
              @onmouseover="() => HoverRating = star"
              @onmouseout="() => HoverRating = null"
              role="button"
              title="@star star(s)">★</span>
    }
</div>

@if (Submitted)
{
    <p class="text-success mt-2">Thanks for rating! You gave @SelectedRating star(s).</p>
}

@if (CurrentRecipe is not null && CurrentRecipe.RatingCount > 0)
{
    <p class="text-muted mt-1">Average: @CurrentRecipe.AverageRating.ToString("0.0") ★ (@CurrentRecipe.RatingCount ratings)</p>
}

<style>
    .star-rating .star {
        font-size: 2rem;
        cursor: pointer;
        color: #ccc;
        transition: color 0.15s;
    }
    .star-rating .star.filled {
        color: #ffc107;
    }
</style>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int SelectedRating { get; set; }
    private int? HoverRating { get; set; }
    private bool Submitted { get; set; }
    private RecipeShare.Models.Recipe? CurrentRecipe { get; set; }

    protected override void OnInitialized()
    {
        CurrentRecipe = RecipeService.GetById(RecipeId);
    }

    private void SubmitRating(int stars)
    {
        SelectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        CurrentRecipe = RecipeService.GetById(RecipeId);
        Submitted = true;
    }
}

@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>

@if (!string.IsNullOrEmpty(SuccessMessage))
{
    <div class="alert alert-success">@SuccessMessage</div>
}

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="Model.Title" />
        <ValidationMessage For="() => Model.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="Model.Category">
            <option value="">-- Select a category --</option>
            <option value="Italian">Italian</option>
            <option value="Indian">Indian</option>
            <option value="Thai">Thai</option>
            <option value="Mexican">Mexican</option>
            <option value="Desserts">Desserts</option>
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => Model.Category" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (comma-separated)</label>
        <InputTextArea id="ingredients" class="form-control" rows="4" @bind-Value="Model.Ingredients" />
        <ValidationMessage For="() => Model.Ingredients" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Model.Steps" />
        <ValidationMessage For="() => Model.Steps" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel Model { get; set; } = new();
    private string? SuccessMessage { get; set; }

    private void HandleSubmit()
    {
        var recipe = RecipeService.Add(Model.Title, Model.Category, Model.Ingredients, Model.Steps);
        SuccessMessage = $"Recipe \"{recipe.Title}\" submitted successfully!";
        Model = new();
    }
}

using System.ComponentModel.DataAnnotations;

