toolArgs.file_text:
@page "/submit"
@rendermode InteractiveServer
@inject RecipeShare.Services.RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>

@if (!string.IsNullOrEmpty(SuccessMessage))
{
    <div class="alert alert-success">@SuccessMessage</div>
}

<EditForm Model="Model" OnValidSubmit="HandleSubmit" FormName="submit-recipe">
    <DataAnnotationsValidator />
    <ValidationSummary />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="Model.Title" />
        <ValidationMessage For="() => Model.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="Model.Category">
            <option value="">-- Select a category --</option>
            <option value="Italian">Italian</option>
            <option value="Indian">Indian</option>
            <option value="Thai">Thai</option>
            <option value="Mexican">Mexican</option>
            <option value="Desserts">Desserts</option>
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => Model.Category" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (comma-separated)</label>
        <InputTextArea id="ingredients" class="form-control" rows="4" @bind-Value="Model.Ingredients" />
        <ValidationMessage For="() => Model.Ingredients" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="Model.Steps" />
        <ValidationMessage For="() => Model.Steps" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel Model { get; set; } = new();
    private string? SuccessMessage { get; set; }

    private void HandleSubmit()
    {
        var recipe = RecipeService.Add(Model.Title, Model.Category, Model.Ingredients, Model.Steps);
        SuccessMessage = $"Recipe \"{recipe.Title}\" submitted successfully!";
        Model = new();
    }
}

using System.ComponentModel.DataAnnotations;

namespace RecipeShare.Models;

public class RecipeFormModel
{
    [Required(ErrorMessage = "Title is required.")]
    [StringLength(100, MinimumLength = 3, ErrorMessage = "Title must be between 3 and 100 characters.")]
    public string Title { get; set; } = string.Empty;

    [Required(ErrorMessage = "Category is required.")]
    public string Category { get; set; } = string.Empty;

    [Required(ErrorMessage = "Ingredients are required.")]
    public string Ingredients { get; set; } = string.Empty;

    [Required(ErrorMessage = "Steps are required.")]
    public string Steps { get; set; } = string.Empty;
}

